// UTILS
function fmt(n){return Math.abs(n).toLocaleString("pt-MZ");}
function ff(n){return fmt(n)+" MT";}
function tod(){return new Date().toLocaleDateString("pt-MZ");}
function tkey(){var d=new Date(new Date().toLocaleString("en-US",{timeZone:"Africa/Maputo"}));return d.getFullYear()+"-"+(d.getMonth()+1)+"-"+d.getDate();}
function n2(){var d=new Date(new Date().toLocaleString("en-US",{timeZone:"Africa/Maputo"}));return String(d.getHours()).padStart(2,"0")+":"+String(d.getMinutes()).padStart(2,"0");}
function isWd(){var d=new Date(new Date().toLocaleString("en-US",{timeZone:"Africa/Maputo"})).getDay();return d>=1&&d<=5;}

function countWeekdays(start,end){
  var count=0;var cur=new Date(start);cur.setHours(0,0,0,0);
  var e=new Date(end);e.setHours(0,0,0,0);
  while(cur<=e){var d=cur.getDay();if(d>=1&&d<=5)count++;cur.setDate(cur.getDate()+1);}
  return count;
}

function addWeekdays(start,n){
  var cur=new Date(start);var count=0;
  while(count<n){cur.setDate(cur.getDate()+1);var d=cur.getDay();if(d>=1&&d<=5)count++;}
  return cur;
}

function getVipDaysLeft(){
  if(!U||!U.vip)return 30; // Default 30 if no date
  if(!U.activated_at)return 30;
  try{
    var parts=U.activated_at.split("/");
    if(parts.length<3)return 30;
    var d=parseInt(parts[0]),m=parseInt(parts[1])-1,y=parseInt(parts[2]);
    if(isNaN(d)||isNaN(m)||isNaN(y)||y<2020)return 30;
    var actDate=new Date(y,m,d);
    var now=new Date();now.setHours(0,0,0,0);
    var elapsed=countWeekdays(actDate,now);
    var left=30-elapsed;
    return Math.max(0,left);
  }catch(e){return 30;}
}

function isVipExpired(){
  if(!U||!U.vip)return false;
  var left=getVipDaysLeft();
  return left!==null&&left<=0;
}
