function mapU(u){
  var n=u.notifications||[];var th=u.task_history||{};var tm=u.team_members||[];
  if(typeof n==="string")try{n=JSON.parse(n);}catch(e){n=[];}
  if(typeof th==="string")try{th=JSON.parse(th);}catch(e){th={};}
  if(typeof tm==="string")try{tm=JSON.parse(tm);}catch(e){tm=[];}
  var rp=u.redeemed_promos||[];if(typeof rp==="string")try{rp=JSON.parse(rp);}catch(e){rp=[];}
  return Object.assign({},u,{vip:u.vip_level?VIPS[u.vip_level-1]:null,balance:parseFloat(u.balance)||0,referrals:u.referrals||0,totalEarned:parseFloat(u.total_earned)||0,refCode:u.ref_code,notifications:n,taskHistory:th,teamMembers:tm,redeemed_promos:rp,fund_unlocked:u.fund_unlocked===true});
}
