async function checkVipExpiry(){
  if(!U||!U.vip)return;
  var left=getVipDaysLeft();
  if(left===null)return;
  U.vipDaysLeft=Math.max(0,left);
  if(left<=0){
    // VIP expired - remove it
    var nn=(U.notifications||[]).concat([{id:Date.now(),msg:"⚠️ O teu VIP "+U.vip.l+" – "+U.vip.n+" expirou! Renova para continuar a ganhar.",time:n2(),date:tod(),read:false}]);
    await syncU({vip:null,notifications:nn});
    // Show expiry alert
    setTimeout(function(){
      toast("⚠️ VIP expirado! Renova para continuar a ganhar.","e");
    },1000);
  } else if(left<=5){
    // Warning - expiring soon
    var warnKey="mz-vip-warn-"+U.phone+"-"+tkey();
    if(!localStorage.getItem(warnKey)){
      localStorage.setItem(warnKey,"1");
      var nn2=(U.notifications||[]).concat([{id:Date.now(),msg:"⏳ O teu VIP "+U.vip.l+" expira em "+left+" dia(s) útil(eis). Renova em breve!",time:n2(),date:tod(),read:false}]);
      await syncU({notifications:nn2});
    }
  }
}
