function renderVips(){
  var maxLvl=U.max_vip_level||0;
  document.getElementById("vip-list").innerHTML=VIPS.map(function(v){
    var act=U.vip&&U.vip.l===v.l;
    var locked=!act&&v.l<maxLvl;
    var btnHtml;
    if(locked){
      btnHtml='<button class="btn-vip" style="background:#1E3060;color:#7090C0;cursor:not-allowed" disabled>🔒 Já tiveste um nível superior</button>';
    } else if(!act){
      btnHtml='<button class="btn-vip" style="background:'+v.c+'" onclick="activVip('+v.l+')">Activar VIP '+v.l+' – '+ff(v.p)+'</button>';
    } else {
      btnHtml='<button class="btn-vip" style="background:'+v.c+';opacity:0.8" onclick="renewVip('+v.l+')">🔄 Renovar – '+ff(v.p)+'</button>';
    }
    return '<div class="vip-card" style="border-color:'+(act?v.c:locked?"#3A2050":"#1E3060")+';opacity:'+(locked?"0.55":"1")+'"><div class="vip-hd"><div class="vip-tag" style="background:'+v.c+'">VIP '+v.l+'</div><div style="color:'+v.c+';font-weight:900">'+v.n+'</div>'+(act?'<div style="margin-left:auto;color:#2ECC71;font-size:13px">✅'+(U.vipDaysLeft?" "+U.vipDaysLeft+"d":"")+'</div>':locked?'<div style="margin-left:auto;color:#7090C0;font-size:13px">🔒</div>':"")+
    '</div><div class="irow"><span class="ilbl">Depósito</span><span class="ival">'+ff(v.p)+'</span></div>'+
    '<div class="irow"><span class="ilbl">Ganho/dia</span><span class="ival" style="color:#00D4FF">'+ff(v.d)+'</span></div>'+
    '<div class="irow"><span class="ilbl">Tarefas/dia</span><span class="ival">'+v.v+'</span></div>'+
    '<div class="irow"><span class="ilbl">Por tarefa</span><span class="ival">'+ff(Math.floor(v.d/v.v))+'</span></div>'+
    '<div class="irow" style="border:none"><span class="ilbl">Validade</span><span class="ival" style="color:#FFD700">30 dias úteis</span></div>'+
    btnHtml+'</div>';
  }).join("");
}
async function activVip(l){
  var v=VIPS[l-1];
  var maxLvl=U.max_vip_level||0;
  if(l<maxLvl){toast("Já tiveste um nível VIP superior. Só podes subir!","e");return;}
  if((U.balance||0)>=v.p){
    await syncU({balance:U.balance-v.p,vip:v,max_vip_level:Math.max(maxLvl,l)});
    earn.push({desc:"💎 VIP "+v.l+" – "+v.n+" activado",a:-v.p,date:tod()});
    // Credit referrer (shared logic, also used when admin approves deposit)
    await creditReferrerOnVip(U.invited_by,U.name,v.l,v.p);
    toast("VIP "+v.l+" "+v.n+" activado! 🚀");renderVips();goTab("t-home","n-home");
  }else{
    depVip=v;
    document.getElementById("dep-vip-box").innerHTML='<div class="vip-card" style="border-color:'+v.c+';margin-bottom:14px"><div style="color:'+v.c+';font-size:15px;font-weight:900;margin-bottom:8px">VIP '+v.l+' – '+v.n+'</div><div class="irow" style="border:none"><span class="ilbl">Valor</span><span class="ival" style="color:#FFD700">'+ff(v.p)+'</span></div></div>';
    goTab("t-deposit","n-none");
  }
}
async function renewVip(l){var v=VIPS[l-1];showConfirm("Renovar VIP "+v.l+"?\nCusto: "+ff(v.p)+"\n30 dias úteis",async function(){if((U.balance||0)<v.p){toast("Saldo insuficiente!","e");return;}await syncU({balance:U.balance-v.p,vip:v});U.vipDaysLeft=30;earn.push({desc:"💎 VIP "+v.l+" – "+v.n+" renovado",a:-v.p,date:tod()});toast("VIP "+v.l+" renovado!");renderVips();});}
function renderVideos(){
  var vg=document.getElementById("vgrid");
  if(!U||!U.vip){
    vg.innerHTML='<div style="background:#2d0a0a;border:2px solid #E74C3C;border-radius:16px;padding:30px;text-align:center;margin:10px 0">'
      +'<div style="font-size:48px;margin-bottom:12px">🔒</div>'
      +'<div style="color:#FF6B6B;font-size:18px;font-weight:900;margin-bottom:10px">VIP Expirado ou Inactivo</div>'
      +'<div style="color:#C8A0A0;font-size:14px;line-height:1.8;margin-bottom:20px">Precisas de um VIP activo para fazer as tarefas e ganhar diariamente.</div>'
      +'<button style="width:100%;padding:14px;background:linear-gradient(135deg,#0050B0,#00D4FF);border:none;border-radius:14px;color:#fff;font-size:16px;font-weight:900;cursor:pointer" onclick=\"goTab(\'t-vips\',\'n-vips\')\">💎 Activar / Renovar VIP</button>'
      +'</div>';
    return;
  }
  if(isFeeOverdue()){
    vg.innerHTML='<div style="background:#2d1500;border:2px solid #FF8C00;border-radius:16px;padding:30px;text-align:center;margin:10px 0">'
      +'<div style="font-size:48px;margin-bottom:12px">💳</div>'
      +'<div style="color:#FF8C00;font-size:18px;font-weight:900;margin-bottom:10px">Taxa Mensal em Atraso</div>'
      +'<div style="color:#C8A070;font-size:14px;line-height:1.8;margin-bottom:20px">Paga a taxa mensal para continuar a fazer tarefas e ganhar.</div>'
      +'<button style="width:100%;padding:14px;background:linear-gradient(135deg,#B8860B,#FFD700);border:none;border-radius:14px;color:#000;font-size:16px;font-weight:900;cursor:pointer" onclick="showMonthlyFee()">💳 Pagar Taxa Mensal</button>'
      +'</div>';
    return;
  }
  // Daily rotating window so extra videos get used (not always the same first N)
  var dayIdx=Math.floor(Date.now()/86400000);
  var startIdx=(dayIdx*7)%VDS.length;
  var rotated=VDS.slice(startIdx).concat(VDS.slice(0,startIdx));
  vg.innerHTML=rotated.slice(0,U.vip.v).map(function(v){
    var dk=done.indexOf(v.id)>=0;
    return '<div class="vcard '+(dk?"done":"")+'" onclick="'+(dk?"":"openVid("+v.id+")")+'">'
      +'<img src="'+v.th+'" alt="'+v.t+'" loading="lazy"/>'
      +'<div class="vbadge">T'+U.vip.l+'</div>'
      +(dk?'<div class="vdone">✓</div>':'<div class="vplay"><div class="vplay-btn">▶</div></div>')
      +'<div class="vinfo">'
      +'<div class="vtit">'+v.t+'</div>'
      +'<div class="vart">'+v.a+'</div>'
      +'<div class="vrwd" style="color:'+(dk?"#2ECC71":"#00D4FF")+'">'+(dk?"Concluído":"+"+Math.floor(U.vip.d/U.vip.v)+" MT")+'</div>'
      +'</div></div>';
  }).join("");
}

var cdT=null;
function openVid(id){
  if(!U||!U.vip){toast("Activa um VIP primeiro!","e");return;}
  if(isFeeOverdue()){toast("Taxa mensal em atraso! Paga para continuar.","e");return;}
  if(!isWd()){toast("Tarefas só Seg-Sex!","e");return;}
  if(done.indexOf(id)>=0){toast("Já assistido hoje!","e");return;}
  if(done.length>=U.vip.v){toast("Limite diário atingido!","e");return;}
  var v=null;
  for(var i=0;i<VDS.length;i++){if(VDS[i].id===id){v=VDS[i];break;}}
  if(!v)return;
  document.getElementById("pl-title").textContent=v.t;
  document.getElementById("pl-artist").textContent=v.a;
  document.getElementById("pl-done").style.display="none";
  document.getElementById("pl-iframe").src="https://www.youtube.com/embed/"+v.yt+"?autoplay=1&rel=0&modestbranding=1&playsinline=1&enablejsapi=1&origin="+encodeURIComponent(window.location.origin);
  var rwd=Math.floor(U.vip.d/U.vip.v);
  document.getElementById("i-artist").textContent=v.a;
  document.getElementById("i-title").textContent=v.t;
  document.getElementById("i-rwd").textContent="+"+ff(rwd)+" MT";
  document.getElementById("cd-earn").textContent="A aguardar o vídeo iniciar...";
  document.getElementById("done-amt").textContent="+"+ff(rwd)+" MT creditados!";
  document.getElementById("cd-card").style.display="block";
  document.getElementById("done-card").style.display="none";
  var numEl=document.getElementById("cd-num");
  if(numEl){numEl.textContent="▶";numEl.style.fontSize="40px";numEl.style.color="#00D4FF";}
  document.getElementById("player").classList.add("on");
  if(cdT){clearInterval(cdT);cdT=null;}
  var cdStarted=false;
  function _start(){
    if(cdStarted)return;
    cdStarted=true;
    window.removeEventListener("message",_ytMsg);
    var earnEl=document.getElementById("cd-earn");
    if(earnEl)earnEl.textContent="+"+ff(rwd)+" MT ao completar";
    if(numEl){numEl.style.fontSize="58px";}
    var t=15;
    if(numEl)numEl.textContent=t;
    cdT=setInterval(async function(){
      t--;
      if(numEl){numEl.textContent=t;numEl.style.color=t<=5?"#E74C3C":"#00D4FF";}
      document.getElementById("i-done").textContent=done.length+"/"+(U.vip?U.vip.v:0);
      document.getElementById("i-rem").textContent=Math.max(0,(U.vip?U.vip.v:0)-done.length);
      if(t<=0){
        clearInterval(cdT);cdT=null;
        document.getElementById("cd-earn").textContent="A confirmar...";
        try{
          var resp=await fetch(FN_COMPLETE_TASK,{
            method:"POST",
            headers:{"Content-Type":"application/json"},
            body:JSON.stringify({phone:U.phone,pin:U.pin,videoId:id})
          });
          var result=await resp.json();
          if(!result.ok){
            toast(result.error||"Não foi possível confirmar.","e");
            document.getElementById("player").classList.remove("on");
            return;
          }
          done.push(id);
          U.balance=result.newBalance;
          U.totalEarned=(U.totalEarned||0)+result.reward;
          earn.push({desc:"🎬 "+v.t,a:result.reward,date:tod()});
          document.getElementById("done-amt").textContent="+"+ff(result.reward)+" MT creditados!";
          document.getElementById("cd-card").style.display="none";
          document.getElementById("done-card").style.display="block";
          document.getElementById("pl-done").style.display="block";
          document.getElementById("i-done").textContent=result.doneCount+"/"+result.limit;
          document.getElementById("i-rem").textContent=Math.max(0,result.limit-result.doneCount);
          renderVideos();
          toast("+"+ff(result.reward)+" MT ganhos! 💰");
        }catch(e){
          toast("Erro de ligação. Tenta novamente.","e");
          document.getElementById("player").classList.remove("on");
        }
      }
    },1000);
  }
  function _ytMsg(e){
    try{
      var d=JSON.parse(e.data);
      if(d&&d.info&&(d.info.playerState===1||d.info.currentTime>0)){_start();}
    }catch(ex){}
  }
  window.addEventListener("message",_ytMsg);
  setTimeout(function(){_start();},4500);
}

function closePlayer(){if(cdT){clearInterval(cdT);cdT=null;}document.getElementById("player").classList.remove("on");document.getElementById("pl-iframe").src="";}
function renderWd(){document.getElementById("wd-amts").innerHTML=[100,500,1000,2000,5000,10000].map(function(a){return '<div class="wda'+(wdAmt===a?" sel":"")+'" onclick="selWd('+a+')">'+fmt(a)+'</div>';}).join("");}
function selWd(a){wdAmt=a;renderWd();}
async function submitWd(){
  if(!wdAmt){toast("Escolhe um valor","e");return;}
  if(!U.vip){toast("Precisas de VIP activo!","e");return;}
  var net=Math.floor(wdAmt*0.9);
  showConfirm("Confirmas levantamento de "+ff(wdAmt)+"?\nTaxa 10% → Recebes "+ff(net),async function(){
    try{
      var resp=await fetch(FN_REQUEST_WITHDRAWAL,{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({phone:U.phone,pin:U.pin,amount:wdAmt})
      });
      var result=await resp.json();
      if(!result.ok){
        toast(result.error||"Não foi possível processar.","e");
        return;
      }
      U.balance=result.newBalance;
      earn.push({desc:"Levantamento",a:-wdAmt,date:tod()});
      window.open("https://wa.me/"+SUP+"?text="+encodeURIComponent("💸 PEDIDO DE LEVANTAMENTO\n👤 "+U.name+"\n📱 "+U.phone+"\n💰 "+wdAmt+" MT → receberá "+result.net+" MT\n🏦 e-Mola\n🕐 "+n2()),"_blank");
      toast("Pedido enviado! ✅");wdAmt=null;renderWd();
    }catch(e){
      toast("Erro de ligação. Tenta novamente.","e");
    }
  });
}
