function tgFundUnlock(phone,name,currentlyUnlocked){
  var u=aU.find(function(x){return x.phone==phone;});
  if(!u)return;
  var willUnlock=!currentlyUnlocked;
  var msg=willUnlock?"Desbloquear o Fundo de Investimento para "+name+"?":"Bloquear o Fundo de Investimento para "+name+"? (Se tiver 5+ indicações, continuará desbloqueado)";
  showConfirm(msg,async function(){
    await DB.upd(phone,{fund_unlocked:willUnlock});
    if(willUnlock){
      var nn=(u.notifications||[]).concat([{id:Date.now(),msg:"🔓 O administrador desbloqueou o Fundo de Investimento na tua conta!",time:n2(),date:tod(),read:false}]);
      await DB.upd(phone,{notifications:nn});
    }
    toast(willUnlock?"Fundo desbloqueado para "+name:"Fundo bloqueado para "+name);
    await loadAdmin();admTab("users");
  });
}

function confirmDeleteUser(phone,name){
  var u=aU.find(function(x){return x.phone==phone;});
  if(!u)return;
  var bal=parseFloat(u.balance)||0;
  var warnBal=bal>0?" ATENCAO: Esta conta tem "+ff(bal)+" de saldo nao levantado!":"";
  showConfirm("Eliminar PERMANENTEMENTE a conta de "+name+" ("+phone+")?"+warnBal+" Esta accao nao pode ser desfeita.",function(){
    showConfirm("Tens MESMO a certeza? Escreve para confirmar: esta accao elimina todos os dados de "+name+" para sempre.",async function(){
      try{
        if(db)await db.from("users").delete().eq("phone",phone);
      }catch(e){}
      var lu=JSON.parse(localStorage.getItem("mz-lu")||"[]");
      lu=lu.filter(function(x){return x.phone!==phone;});
      localStorage.setItem("mz-lu",JSON.stringify(lu));
      var delCount=parseInt(localStorage.getItem("mz-del-count")||"0")+1;
      localStorage.setItem("mz-del-count",String(delCount));
      toast("Conta de "+name+" eliminada.","e");
      await loadAdmin();admTab("users");
    });
  });
}

