function copyPromoLink(link){
  if(navigator.clipboard){
    navigator.clipboard.writeText(link).then(function(){toast("Link copiado!");}).catch(function(){toast("Link: "+link);});
  } else {
    toast("Link: "+link);
  }
}

function createPromo(){var code=document.getElementById("pc").value.trim().toUpperCase(),bonus=parseInt(document.getElementById("pb").value||0),uses=parseInt(document.getElementById("pu").value||100);if(!code||!bonus){toast("Preenche código e bónus","e");return;}var promos=JSON.parse(localStorage.getItem("mz-promos")||"{}");promos[code]={bonus:bonus,max:uses,used:0,created:tod()};localStorage.setItem("mz-promos",JSON.stringify(promos));toast("Código "+code+" criado! ✅");admPromo();}
function delPromo(code){var promos=JSON.parse(localStorage.getItem("mz-promos")||"{}");delete promos[code];localStorage.setItem("mz-promos",JSON.stringify(promos));toast("Removido","e");admPromo();}



// ─── SUPPORT TICKETS ─────────────────────────────────────
function switchSupport(tab){
  ["contact","ticket","mytickets"].forEach(function(t){
    var el=document.getElementById("s-"+t);if(el)el.style.display=t===tab?"block":"none";
    var stEl=document.getElementById("st-"+t);if(stEl)stEl.classList.toggle("on",t===tab);
  });
  if(tab==="mytickets")renderMyTickets();
}

function submitTicket(){
  var subj=document.getElementById("tk-subject").value;
  var desc=document.getElementById("tk-desc").value.trim();
  if(!desc){toast("Descreve o teu problema","e");return;}
  var tickets=JSON.parse(localStorage.getItem("mz-tickets-"+(U?U.phone:""))||"[]");
  var subjLabels={"deposit":"Depósito","withdrawal":"Levantamento","vip":"VIP","tasks":"Tarefas","account":"Conta","other":"Outro"};
  var ticket={id:"TK"+Date.now(),subject:subjLabels[subj]||subj,desc:desc,date:tod(),time:n2(),status:"pending"};
  tickets.push(ticket);
  localStorage.setItem("mz-tickets-"+(U?U.phone:""),JSON.stringify(tickets));
  // Save to Supabase too so admin can see ALL tickets in one place
  DB.txSave({user_id:U.phone,user_name:U.name,phone:U.phone,amount:0,type:"ticket",note:ticket.subject+": "+desc,status:"pending"});
  // Send to WhatsApp
  var waMsg=encodeURIComponent("🎫 TICKET DE SUPORTE\n\n👤 "+U.name+"\n📱 +258 "+U.phone+"\n📋 Assunto: "+ticket.subject+"\n\n"+desc+"\n\n🆔 "+ticket.id);
  window.open("https://wa.me/"+SUP+"?text="+waMsg,"_blank");
  document.getElementById("tk-desc").value="";
  toast("Ticket enviado! ✅ Aguarda resposta.");
  switchSupport("mytickets");
}

async function renderMyTickets(){
  var el=document.getElementById("my-tickets-list");if(!el)return;
  el.innerHTML='<div class="empty">A carregar...</div>';
  var tickets=[];
  // Try to fetch live status from Supabase (source of truth for status)
  if(db&&U){
    try{
      var r=await db.from("transactions").select("*").eq("phone",U.phone).eq("type","ticket").order("created_at",{ascending:false});
      if(r.data){
        tickets=r.data.map(function(t){
          var parts=(t.note||"").split(": ");
          var subj=parts.length>1?parts[0]:"Suporte";
          var desc=parts.length>1?parts.slice(1).join(": "):(t.note||"");
          var dt=t.created_at?new Date(t.created_at):null;
          return {subject:subj,desc:desc,status:t.status||"pending",date:dt?dt.toLocaleDateString("pt-MZ"):"—",time:dt?dt.toLocaleTimeString("pt-MZ",{hour:"2-digit",minute:"2-digit"}):"",id:t.id};
        });
      }
    }catch(e){}
  }
  // Fallback to local copy if no DB or empty
  if(tickets.length===0){
    tickets=JSON.parse(localStorage.getItem("mz-tickets-"+(U?U.phone:""))||"[]");
  }
  if(tickets.length===0){el.innerHTML='<div class="empty">Sem tickets ainda</div>';return;}
  el.innerHTML=tickets.map(function(t){
    var sCol=t.status==="resolved"?"#2ECC71":t.status==="pending"?"#FFD700":"#00D4FF";
    var sLbl=t.status==="resolved"?"✅ Resolvido":t.status==="pending"?"⏳ Pendente":"💬 Em análise";
    return '<div class="card" style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;margin-bottom:8px"><div style="font-weight:900;font-size:14px">'+t.subject+'</div><span style="font-size:12px;font-weight:900;color:'+sCol+'">'+sLbl+'</span></div><div style="color:#7090C0;font-size:13px;line-height:1.6;margin-bottom:8px">'+t.desc+'</div><div style="color:#3A5070;font-size:11px">'+t.date+' '+t.time+'</div></div>';
  }).join("");
}

// ─── VIP HISTORY ─────────────────────────────────────────
function renderVipHist(){
  var hist=earn.filter(function(e){return e.desc&&e.desc.includes("VIP");});
  var el=document.getElementById("vip-hist-list");if(!el)return;
  // Also add current VIP
  var current=U&&U.vip?[{desc:"💎 VIP "+U.vip.l+" – "+U.vip.n+" (Activo)",date:U.activated_at||tod(),status:"active",color:U.vip.c}]:[];
  var all=current.concat(hist.slice().reverse().map(function(e){return {desc:e.desc,date:e.date,status:"past",a:e.a};}));
  if(all.length===0){el.innerHTML='<div class="empty">Sem histórico de VIPs</div>';return;}
  el.innerHTML=all.map(function(v){
    var dLeft=v.status==="active"?getVipDaysLeft():null;
    return '<div class="card" style="border-color:'+(v.color||"#0D2A4A")+'">'+'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">'+'<div style="font-weight:900;font-size:14px">'+v.desc+'</div>'+(v.status==="active"?'<span style="background:#2ECC71;border-radius:20px;padding:3px 10px;font-size:11px;font-weight:900;color:#000">✅ Activo</span>':'<span style="color:#5070A0;font-size:12px">Concluído</span>')+'</div>'+(v.status==="active"&&dLeft!==null?'<div class="irow" style="border:none"><span class="ilbl">⏳ Dias restantes</span><span class="ival" style="color:'+(dLeft<=5?"#FF6B6B":"#FFD700")+'">'+Math.max(0,dLeft)+' dias úteis</span></div>':'')+'<div style="color:#3A5070;font-size:12px;margin-top:6px">📅 '+v.date+'</div></div>';
  }).join("");
}




