async function applyPendingPromo(){
  if(!U)return;
  var pending=null;
  try{pending=localStorage.getItem("mz-pending-promo");}catch(e){}
  if(!pending)return;
  try{localStorage.removeItem("mz-pending-promo");}catch(e){}
  var promos=JSON.parse(localStorage.getItem("mz-promos")||"{}");
  var info=promos[pending];
  if(!info)return; // code no longer exists
  if((info.used||0)>=info.max){toast("Código "+pending+" esgotado.","e");return;}
  var redeemed=U.redeemed_promos||[];
  if(typeof redeemed==="string")try{redeemed=JSON.parse(redeemed);}catch(e){redeemed=[];}
  if(redeemed.indexOf(pending)>=0){return;} // already used by this account
  // Apply bonus
  var bonus=info.bonus||0;
  redeemed.push(pending);
  info.used=(info.used||0)+1;
  promos[pending]=info;
  localStorage.setItem("mz-promos",JSON.stringify(promos));
  var nn=(U.notifications||[]).concat([{id:Date.now(),msg:"🎁 Código promocional "+pending+" aplicado! +"+ff(bonus)+" creditados.",time:n2(),date:tod(),read:false}]);
  await syncU({balance:(U.balance||0)+bonus,totalEarned:(U.totalEarned||0)+bonus,notifications:nn,redeemed_promos:redeemed});
  toast("🎁 +"+ff(bonus)+" creditados pelo código "+pending+"!");
}


// ─── SHARED: Credit referrer when ANY VIP gets activated (direct OR via deposit approval) ───
async function creditReferrerOnVip(invitedByCode, activatorName, vipLevel, vipPrice){
  if(!invitedByCode||!db)return;
  try{
    var refr=await db.from("users").select("*").eq("ref_code",invitedByCode).single();
    if(refr.data){
      var rfu=refr.data;
      var newRefCount=(rfu.referrals||0)+1;
      var refBonus=RB[newRefCount]||0;
      var refNn=(rfu.notifications||[]).concat([{id:Date.now(),msg:"🎉 "+activatorName+" activou VIP "+vipLevel+"! "+newRefCount+"/5."+(refBonus>0?" Bónus de "+ff(refBonus)+" creditado! 💰":""),time:n2(),date:tod(),read:false}]);
      var refPatch={referrals:newRefCount,notifications:refNn};
      if(refBonus>0){refPatch.balance=(parseFloat(rfu.balance)||0)+refBonus;refPatch.total_earned=(parseFloat(rfu.total_earned)||0)+refBonus;}
      await DB.upd(rfu.phone,refPatch);
      // Level 2 bonus
      if(rfu.invited_by){
        try{
          var gp=await db.from("users").select("*").eq("ref_code",rfu.invited_by).single();
          if(gp.data){
            var gb=Math.floor(vipPrice*0.02);
            var gpnn=(gp.data.notifications||[]).concat([{id:Date.now(),msg:"🎁 Bónus nível 2: +"+ff(gb)+" (indicado activou VIP "+vipLevel+")",time:n2(),date:tod(),read:false}]);
            await DB.upd(gp.data.phone,{balance:(parseFloat(gp.data.balance)||0)+gb,total_earned:(parseFloat(gp.data.total_earned)||0)+gb,notifications:gpnn});
          }
        }catch(e){}
      }
    }
  }catch(e){}
}